type BaseParserType<'input, I> =
	BaseParser<'input,ProcDSLParserExt<'input>, I, ProcDSLParserContextType , dyn ProcDSLListener<'input> + 'input >;

type TokenType<'input> = <LocalTokenFactory<'input> as TokenFactory<'input>>::Tok;
pub type LocalTokenFactory<'input> = CommonTokenFactory;

pub type ProcDSLTreeWalker<'input,'a> =
	ParseTreeWalker<'input, 'a, ProcDSLParserContextType , dyn ProcDSLListener<'input> + 'a>;

/// Parser for ProcDSL grammar
pub struct ProcDSLParser<'input,I,H>
where
    I: TokenStream<'input, TF = LocalTokenFactory<'input> > + TidAble<'input>,
    H: ErrorStrategy<'input,BaseParserType<'input,I>>
{
	base:BaseParserType<'input,I>,
	interpreter:Arc<ParserATNSimulator>,
	_shared_context_cache: Box<PredictionContextCache>,
    pub err_handler: H,
}

impl<'input, I, H> ProcDSLParser<'input, I, H>
where
    I: TokenStream<'input, TF = LocalTokenFactory<'input> > + TidAble<'input>,
    H: ErrorStrategy<'input,BaseParserType<'input,I>>
{
	pub fn get_serialized_atn() -> &'static str { _serializedATN }

    pub fn set_error_strategy(&mut self, strategy: H) {
        self.err_handler = strategy
    }

    pub fn with_strategy(input: I, strategy: H) -> Self {
		antlr_rust::recognizer::check_version("0","3");
		let interpreter = Arc::new(ParserATNSimulator::new(
			_ATN.clone(),
			_decision_to_DFA.clone(),
			_shared_context_cache.clone(),
		));
		Self {
			base: BaseParser::new_base_parser(
				input,
				Arc::clone(&interpreter),
				ProcDSLParserExt{
					_pd: Default::default(),
				}
			),
			interpreter,
            _shared_context_cache: Box::new(PredictionContextCache::new()),
            err_handler: strategy,
        }
    }

}

type DynStrategy<'input,I> = Box<dyn ErrorStrategy<'input,BaseParserType<'input,I>> + 'input>;

impl<'input, I> ProcDSLParser<'input, I, DynStrategy<'input,I>>
where
    I: TokenStream<'input, TF = LocalTokenFactory<'input> > + TidAble<'input>,
{
    pub fn with_dyn_strategy(input: I) -> Self{
    	Self::with_strategy(input,Box::new(DefaultErrorStrategy::new()))
    }
}

impl<'input, I> ProcDSLParser<'input, I, DefaultErrorStrategy<'input,ProcDSLParserContextType>>
where
    I: TokenStream<'input, TF = LocalTokenFactory<'input> > + TidAble<'input>,
{
    pub fn new(input: I) -> Self{
    	Self::with_strategy(input,DefaultErrorStrategy::new())
    }
}

/// Trait for monomorphized trait object that corresponds to the nodes of parse tree generated for ProcDSLParser
pub trait ProcDSLParserContext<'input>:
	for<'x> Listenable<dyn ProcDSLListener<'input> + 'x > + 
	for<'x> Visitable<dyn ProcDSLVisitor<'input> + 'x > + 
	ParserRuleContext<'input, TF=LocalTokenFactory<'input>, Ctx=ProcDSLParserContextType>
{}

antlr_rust::coerce_from!{ 'input : ProcDSLParserContext<'input> }

impl<'input, 'x, T> VisitableDyn<T> for dyn ProcDSLParserContext<'input> + 'input
where
    T: ProcDSLVisitor<'input> + 'x,
{
    fn accept_dyn(&self, visitor: &mut T) {
        self.accept(visitor as &mut (dyn ProcDSLVisitor<'input> + 'x))
    }
}

impl<'input> ProcDSLParserContext<'input> for TerminalNode<'input,ProcDSLParserContextType> {}
impl<'input> ProcDSLParserContext<'input> for ErrorNode<'input,ProcDSLParserContextType> {}

antlr_rust::tid! { impl<'input> TidAble<'input> for dyn ProcDSLParserContext<'input> + 'input }

antlr_rust::tid! { impl<'input> TidAble<'input> for dyn ProcDSLListener<'input> + 'input }

pub struct ProcDSLParserContextType;
antlr_rust::tid!{ProcDSLParserContextType}

impl<'input> ParserNodeType<'input> for ProcDSLParserContextType{
	type TF = LocalTokenFactory<'input>;
	type Type = dyn ProcDSLParserContext<'input> + 'input;
}

